import React from "react";
import { useNavigate } from "react-router-dom";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function Tools({ employee }) {
  const navigate = useNavigate();

  return (
    <div style={outer}>
      <div style={card}>
        
        {/* HEADER */}
        <div style={headerRow}>
          <button onClick={() => navigate("/home")} style={backBtn}>⬅</button>
          <h2 style={title}>Tools</h2>
        </div>

        <p style={empInfo}>Employee: {employee.name} • {employee.empld}</p>

        {/* TOOL CARDS */}
        <div style={toolsWrapper}>

          {/* Monthly Expense Graph */}
          <div style={toolCard} onClick={() => navigate("/tools/graph")}>
            <h3 style={cardTitle}>Monthly Expense Graph</h3>
            <p style={cardText}>View monthly travel & ticket spending</p>
          </div>

        </div>
      </div>
    </div>
  );
}

/* ----------------------------- STYLES ------------------------------ */

const outer = {
  background: lightGreen,
  minHeight: "100vh",
  padding: "30px 10px",
  display: "flex",
  justifyContent: "center",
};

const card = {
  width: "100%",
  maxWidth: "780px",
  background: "#fff",
  padding: "25px",
  borderRadius: "16px",
  boxShadow: "0 4px 18px rgba(0,0,0,0.08)",
};

const headerRow = {
  display: "flex",
  alignItems: "center",
  gap: "15px",
};

const backBtn = {
  background: lightGreen,
  border: "none",
  padding: "10px 14px",
  borderRadius: "10px",
  cursor: "pointer",
  fontSize: "18px",
};

const title = {
  color: green,
  margin: 0,
};

const empInfo = {
  color: "#777",
  marginTop: "8px",
  marginBottom: "25px",
};

const toolsWrapper = {
  display: "flex",
  flexDirection: "column",
  gap: "15px",
};

const toolCard = {
  background: lightGreen,
  padding: "20px",
  borderRadius: "14px",
  borderLeft: `6px solid ${green}`,
  cursor: "pointer",
  transition: "0.2s",
};

const cardTitle = {
  margin: 0,
  color: green,
  fontSize: "20px",
};

const cardText = {
  margin: "5px 0 0",
  color: "#555",
};
